  <div class="container">
      <span>
        <gallery-menu
        @toggle-gallery='updateShowGallery($event)'
        :disableGallery='disableGallery'/>
        <profile/>
        <contentSection
        @gallery-disable='updateDisableGallery($event)'
        :showGallery='showGallery'/>
      </span>
