  </div>
</template>

<script>
import galleryMenu from '@/components/galleryMenu';
import profile from '@/components/profile';
import contentSection from '@/components/content';
import {ref} from 'vue';

export default {
  components: {
    galleryMenu,
    profile,
    contentSection,
  },
  setup () {
    const showGallery = ref(false);
    const disableGallery = ref(false);
    const updateShowGallery = (e) => {
      showGallery.value = e;
    };
    const updateDisableGallery = (e) => {
      disableGallery.value = e
    };
    return {
      showGallery,
      disableGallery,
      updateShowGallery,
      updateDisableGallery,
    };
  },
}
</script>

