<template>
    <teleport to="#app">
        <transition name="nice">
            <div id="niceFade" v-show="interestedState" class="niceContainer">
                <img :style="{'margin':'auto'}" src="../assets/rating.png" alt="nice">
            </div>
        </transition>
    </teleport>
    <teleport to="#app">
        <transition name="nice">
            <div id="galleryFade" v-show="fadeToGray" class="niceContainer">
              <span class="galleryGuide"
              :style="{'height': galleryGuideSize.height, 'width': galleryGuideSize.width}">
              </span>
            </div>
        </transition>
    </teleport>
    <span class="detailContainer">
      <div class="section">
        I'M KEB
      </div>
      <div>
        <p>
          "Ultimately, everything happens when we are ready for them to happen.
          So be patient, focus on yourself, and let time give you what you deserve when you deserve it."
        </p>
      </div>
      <div class="section">
        WHAT I LOVE TO DO
      </div>
      <div>
        <p>
          <button
          @click="onClick"
          v-show="!interestedState && !endOfNice">
            Interested?
          </button>
          <span id="loveToDo"></span>
          <transition name="boomContainerTransition">
              <div v-if="endOfFirst" class="boomContainer">
                  <transition name="boom">
                      <img
                      :style="{'height':'100%', 'z-index': 1}"
                      v-show="boomImage"
                      src="../assets/boom.png"
                      alt="boom">
                  </transition>
              </div>
          </transition>
          <br/>
          <br/>
          <span id="afterBoom"></span>
        </p>
      </div>
    </span>
</template>

<script>
import { ref, reactive, watch } from 'vue';
export default {
    emits: [
      'gallery-disable',
      ],
    props: {
      showGallery: {
        type: Boolean
      },
    },
    setup(props, { emit }) {
        const interestedState = ref(false);
        const endOfNice = ref(false);
        const endOfFirst = ref(false);
        const endOfBoom = ref(false);
        const boomImage = ref(false);
        const fadeToGray = ref(false);
        const afterGallery = ref(0);
        const galleryGuideSize = reactive({
          height: null,
          width: null,
        });
        const loveToDo = 'Well for starters, I LOVE to code... REALLY! Don\'t believe me? Check this out.';
        const afterBoom = 'Pretty engaging, right? There\'s plenty more where that came from.';
        const photoSentence = 'I also LOVE taking pictures. I have a Canon M50 camera that\'s pretty lightweight. ' +
        'I carry that everytime I travel. You can actually route over to the gallery to see some of it. Here, let me guide you.';
        const afterGallerySentence = 'AWESOME! Let me speed things up, here\'s a list of the other things I LOVE:' ;
        const finalizeSentence = 'With that, I guess that\'s all the highlights I can cover regarding my life. ' +
        'If you have any more questions or just want to chat, you can always ping me on the environments I added right below my photo.';
        const goodByeSentence = 'TAKE CARE! Goodbye, Paalam, Sayonara, Au revoir!';
        const loveItemized = [
          '-Family',
          '-Music (BONUS: I\'m a bassist)',
          '-Food (Who doesn\'t?)',
          '-Travelling',
          '-Socializing. Like, just talk and hang out or while simply grabbing a cup of coffee',
          ];

        const speed = 50;
        let i = 0;
        const onClick = () => {
            interestedState.value = true;
            emit('gallery-disable', true);
        };
        const typeAfterNice = () => {
            if (i < loveToDo.length) {
                document.getElementById("loveToDo").innerHTML += loveToDo.charAt(i);
                i++;
                setTimeout(typeAfterNice, speed);
            } else {
                endOfFirst.value = true;
                setTimeout(() => {
                    boomImage.value = true;
                },500);
                i = 0;
            }
        };

        const typePhotoSentence = () => {
            if (i < photoSentence.length) {
                document.getElementById("afterBoom").innerHTML += photoSentence.charAt(i);
                i++;
                setTimeout(typePhotoSentence, speed);
            } else {
              emit('gallery-disable', false);
              setTimeout(()=>{fadeToGray.value = true}, 1000);
              galleryGuideSize.height = `${document.getElementById('galleryButton').getBoundingClientRect().height}px`;
              galleryGuideSize.width = `${document.getElementById('galleryButton').getBoundingClientRect().height}px`;
              document.getElementById("afterBoom").innerHTML += '<br/><br/>';
              i = 0;
            }
        };

        const typeAfterBoom = () => {
            if (i < afterBoom.length) {
              document.getElementById("afterBoom").innerHTML += afterBoom.charAt(i);
              i++;
              setTimeout(typeAfterBoom, speed);
            } else {
              document.getElementById("afterBoom").innerHTML += '<br/><br/>';
              i = 0;
              typePhotoSentence();
            }
        };

        const typeGoodbye = () => {
            if (i < goodByeSentence.length) {
              document.getElementById("afterBoom").innerHTML += goodByeSentence.charAt(i);
              i++;
              setTimeout(typeGoodbye, speed);
            } else {
              i = 0;
            }
        };

        const typeFinalize = () => {
            if (i < finalizeSentence.length) {
              document.getElementById("afterBoom").innerHTML += finalizeSentence.charAt(i);
              i++;
              setTimeout(typeFinalize, speed);
            } else {
              document.getElementById("afterBoom").innerHTML += '<br/><br/>';
              i = 0;
              typeGoodbye();
            }
        };

        const typeAllLove = (love, index) => {
          if (i < love.length) {
              document.getElementById("afterBoom").innerHTML += love.charAt(i);
              i++;
              setTimeout(typeAllLove(love,index), speed);
            } else {
              document.getElementById("afterBoom").innerHTML += '<br/>';
              i = 0;
              if (index === loveItemized.length - 1) {
                document.getElementById("afterBoom").innerHTML += '<br/>';
                setTimeout(typeFinalize(),1000);
              }
            }
        };

        const getAllLove = () => {
          for (let j = 0; j < loveItemized.length; j += 1) {
            typeAllLove(loveItemized[j],j);
          }
        };

        const typeAfterGallery = () => {
            if (i < afterGallerySentence.length) {
              document.getElementById("afterBoom").innerHTML += afterGallerySentence.charAt(i);
              i++;
              setTimeout(typeAfterGallery, speed);
            } else {
              document.getElementById("afterBoom").innerHTML += '<br/>';
              i = 0;
              getAllLove();
            }
        };

        watch(() => props.showGallery, (newValue) => {
          if (fadeToGray.value) {
            fadeToGray.value = false;
            afterGallery.value += 1;
          } else if (afterGallery.value === 1) {
            typeAfterGallery();
            afterGallery.value += 1;
          }
        });

        watch(boomImage, (newValue) => {
          if (newValue) {
            setTimeout(()=>{
                boomImage.value = false;
                endOfFirst.value = false;
                typeAfterBoom();
            },1000);
          }
        });

        watch(interestedState, (newValue) => {
          if (newValue) {
            setTimeout(()=>{
                interestedState.value = false;
                endOfNice.value = true;
                typeAfterNice();
            },1000);
          }
        });

        return{
            interestedState,
            endOfNice,
            endOfFirst,
            boomImage,
            fadeToGray,
            galleryGuideSize,
            onClick,
        };
    }
}
</script>

