<template>
    <span id='galleryMenuContainer' class="navMenu-normal">
      <div v-if='showGallery' class="galleryLoadingContainer">
        <!-- <img src="../assets/loading.gif" alt="load" class="galleryLoading">
        <div>LOADING</div> -->
        <!-- <vueper-slides> -->
          <span
          :style="{'filter': 'drop-shadow(2px 4px white)'}">
            THE GALLERY
          </span>
          <vueper-slides
          autoplay
          duration="3000"
          :style="{'filter': 'drop-shadow(2px 4px 6px black) ' + addFilter}"
          lazy
          lazy-load-on-drag
          :arrows="false"
          fixed-height="100%">
            <vueper-slide v-for="(item,n) in galleryItem" :key="n"
              :image="item">
              <template v-slot:loader>
                <i class="icon icon-loader spinning"></i>
                <span>
                  <img src="../assets/loading.gif" alt="load" class="galleryLoading">
                </span>
              </template>
            </vueper-slide>
          </vueper-slides>
          <span
          :style="{'font-size':'large'}">EFFECTS:
          </span>
          <button
          title="Grayscale"
          class="buttonFilter"
          :style="{'background':'dimgray'}"
          @click="filterGrayScale"
          />
          <button
          title="Sepia"
          class="buttonFilter"
          :style="{'background':'#c5b457'}"
          @click="filterSepia"
          />
          <button class="buttonFilter"
          title="Remove effects"
          @click="filterNormal"
          />
      </div>
      <img
      id='galleryButton'
      class="galleryMenu-normal"
      :style="{'width': btnWidth, 'pointer-events': btnPointer}"
      src="https://www.flaticon.com/svg/static/icons/svg/724/724954.svg"
      alt="Menu"
      @click="onClickGallery">
    </span>
</template>

<script>
import { ref, watch } from 'vue';
import { VueperSlides, VueperSlide } from 'vueperslides'
import 'vueperslides/dist/vueperslides.css'

export default {
  emits: [
    'toggle-gallery'
  ],
  props: {
    disableGallery: {
      type: Boolean,
    },
  },
  components: {
    VueperSlides,
    VueperSlide,
  },
  setup(props,{ emit }) {
    const galleryItem = [
      require('../assets/gallery/1.jpg'),
      require('../assets/gallery/2.jpg'),
      require('../assets/gallery/3.jpg'),
      require('../assets/gallery/4.jpg'),
      require('../assets/gallery/5.jpg'),
      require('../assets/gallery/6.jpg'),
      require('../assets/gallery/7.jpg'),
      require('../assets/gallery/8.jpg'),
      require('../assets/gallery/9.jpg'),
    ];
    const showGallery = ref(false);
    const btnWidth = ref('50%');
    const btnPointer = ref('all');
    const addFilter = ref('');
    const onClickGallery = () => {
      showGallery.value = !showGallery.value;
      emit('toggle-gallery', showGallery.value);
      if (showGallery.value) {
        btnWidth.value = `${document.getElementById('galleryButton').getBoundingClientRect().width}px`;
        document.getElementById('galleryMenuContainer').className = 'navMenu-grow';
        document.getElementById('galleryButton').className = 'galleryMenu-flip';

      } else {
        btnWidth.value = '50%'
        document.getElementById('galleryMenuContainer').className = 'navMenu-normal';
        document.getElementById('galleryButton').className = 'galleryMenu-normal';
      }
    };
    const filterNormal = () => {
      addFilter.value = '';
    };
    const filterGrayScale = () => {
      addFilter.value = 'grayscale(1)';
    };
    const filterSepia = () => {
      addFilter.value = 'sepia(0.7)';
    };

    watch(() => props.disableGallery, (newValue) => {
          if (newValue) {
            btnPointer.value = 'none';
          } else {
            btnPointer.value = 'all';
          }
        });
    return {
      addFilter,
      galleryItem,
      showGallery,
      btnWidth,
      btnPointer,
      onClickGallery,
      filterNormal,
      filterGrayScale,
      filterSepia,
    };
  },
}
</script>

<style scoped>
