  width: 4%;
  transition-duration: .5s;
}
.navMenu-grow {
  width: 60%;
  transition-duration: .5s;
}

#galleryButton {
  position: absolute;
  top: 50%;
  right: 0px;
  z-index: 2;
}
#galleryButton:hover{
  filter: invert(1);
}


.galleryMenu-normal {
  transform: translateY(-50%) scale(1);
  padding-right: 25%;
  transition-duration: .5s;
}

.galleryMenu-flip {
  transform: translateY(-50%) scale(-1);
  padding-left: 15px;
  transition-duration: .5s;
}

.showGalleryTransition-enter-active {
    transition: width .1s linear;
}
.showGalleryTransition-leave-active {
    transition: width .05s linear;
}
.showGalleryTransition-enter-from, .showGalleryTransition-leave-to {
    width: 100%;
}

.galleryLoadingContainer {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 80%;
  height: 50%;
  transform: translate(-50%, -50%);
  font-family: 'Comfortaa';
  font-size: -webkit-xxx-large;
  font-weight: bolder;

}

.galleryLoading {
  border-radius: 100%;
  filter: drop-shadow(2px 4px 6px black);
  width: 50%;
}

.thumbnails {
  margin: auto;
  max-width: 300px;
}

.thumbnails .vueperslide {
  box-sizing: border-box;
  border: 1px solid #fff;
  transition: 0.3s ease-in-out;
  opacity: 0.7;
  cursor: pointer;
}

.thumbnails .vueperslide--active {
  box-shadow: 0 0 6px rgba(0, 0, 0, 0.3);
  opacity: 1;
